sql.oracle:
CREATE TABLE BPQMNC_FASE (
    IDFASE     NUMBER(10,0)  NOT NULL,
    DESCFASE   VARCHAR2(100) NOT NULL,
    ATIVO      CHAR(1)       DEFAULT 'S' NOT NULL,
    CONSTRAINT PK_BPQM_NC_FASE    PRIMARY KEY (IDFASE),
    CONSTRAINT CK_BPQM_NC_FASE_AT CHECK (ATIVO IN ('S','N'))
);
COMMENT ON TABLE  BPQMNC_FASE          IS 'QualityManager: fases do workflow de NC (1 a 10)';
COMMENT ON COLUMN BPQMNC_FASE.IDFASE   IS '1=Registro, 2=Acoes Imediatas, 3=Causa Raiz, 4=Abrangencia, 5=Acoes Corretivas, 6=Revisao Doc, 7=Riscos, 8=Implementacao, 9=Liberacao, 10=Verificacao Eficacia';

DECLARE v_qtde NUMBER;
BEGIN
    SELECT COUNT(*) INTO v_qtde FROM BPQMNC_FASE;
    IF v_qtde = 0 THEN
        INSERT INTO BPQMNC_FASE (IDFASE, DESCFASE) VALUES  (1, 'Registro de Nao Conformidade');
        INSERT INTO BPQMNC_FASE (IDFASE, DESCFASE) VALUES  (2, 'Acoes Imediatas');
        INSERT INTO BPQMNC_FASE (IDFASE, DESCFASE) VALUES  (3, 'Causa Raiz');
        INSERT INTO BPQMNC_FASE (IDFASE, DESCFASE) VALUES  (4, 'Abrangencia');
        INSERT INTO BPQMNC_FASE (IDFASE, DESCFASE) VALUES  (5, 'Acoes Corretivas');
        INSERT INTO BPQMNC_FASE (IDFASE, DESCFASE) VALUES  (6, 'Revisao de Documentos');
        INSERT INTO BPQMNC_FASE (IDFASE, DESCFASE) VALUES  (7, 'Riscos e Oportunidades');
        INSERT INTO BPQMNC_FASE (IDFASE, DESCFASE) VALUES  (8, 'Implementacao');
        INSERT INTO BPQMNC_FASE (IDFASE, DESCFASE) VALUES  (9, 'Liberacao de Produto');
        INSERT INTO BPQMNC_FASE (IDFASE, DESCFASE) VALUES (10, 'Verificacao de Eficacia');
        COMMIT;
    END IF;
END;

