sql.oracle:
CREATE OR REPLACE TRIGGER TRG_BPQM_NC_REGISTRO_BI
BEFORE INSERT ON BPQMNC_REGISTRO
FOR EACH ROW
DECLARE
    v_ano VARCHAR2(4);
BEGIN
    IF :NEW.IDNC IS NULL THEN
        SELECT SEQ_BPQM_NC_REGISTRO.NEXTVAL INTO :NEW.IDNC FROM DUAL;
    END IF;
    IF :NEW.NUMNC IS NULL THEN
        v_ano := TO_CHAR(SYSDATE, 'YYYY');
        :NEW.NUMNC := 'NC-' || v_ano || '-' || LPAD(:NEW.IDNC, 4, '0');
    END IF;
    :NEW.IDFASE    := 1;
    :NEW.STATUS    := 'A';
    :NEW.DTCRIACAO := SYSDATE;
END;

CREATE TABLE BPQMNC_REG_FASES (
    IDREGFASE    NUMBER(10,0)  NOT NULL,
    IDNC         NUMBER(10,0)  NOT NULL,
    IDFASE       NUMBER(10,0)  NOT NULL,
    DTFASE       DATE          DEFAULT SYSDATE NOT NULL,
    CODUSU       NUMBER(38,0)  NOT NULL,
    CONSTRAINT PK_BPQM_NC_REG_FASES PRIMARY KEY (IDREGFASE)
);
COMMENT ON TABLE  BPQMNC_REG_FASES       IS 'QualityManager: historico de transicoes de fase por NC — auditoria ISO 9001';
COMMENT ON COLUMN BPQMNC_REG_FASES.IDNC  IS 'FK -> BPQMNC_REGISTRO.IDNC';

ALTER TABLE BPQMNC_REG_FASES
    ADD CONSTRAINT FK_BPQM_NC_REG_FASES_NC
    FOREIGN KEY (IDNC) REFERENCES BPQMNC_REGISTRO (IDNC);

